VALUES
  ('cpa-moex-00951', 'cpa', 'cpa-moex-106-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員執行控制測試而使用統計抽樣時，下列敘述何者正確？', '["通常假設母體的規模很大，如果母體的規模不大，查核人員應採取抽出再放回的選樣方式，以選 取樣本", "使用的抽樣方法稱為變量抽樣法（variable sampling）", "其他因素不變的情形下，查核人員若將過度信賴風險訂得越高，則所需的樣本量越大", "當最大可容忍偏差率與預期母體偏差率差距越小時，則所需的樣本量越小"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "1491f6c398c7", "answer_pdf_sha1": "19aa8285bb8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00952', 'cpa', 'cpa-moex-106-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員決定是否採用證實分析性程序，下列何者為其主要考量因素？', '["辨認及評估財務報表重大不實表達風險", "與分析性程序的效率及效果有關之因素", "可取得高度整合之證據", "查核人員對受查者所屬之產業較熟悉，且執行測試的時間通常在資產負債表日之前實施，可減輕 期末查核工作的壓力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "1491f6c398c7", "answer_pdf_sha1": "19aa8285bb8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00953', 'cpa', 'cpa-moex-106-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '受查者的採購及付款循環的內部控制存有重大缺失，廠長常訂購超額的原料，並指定將超額訂購的 原料送至其自行經營的另一家公司。廠長偽造驗收文件並且核准付款支票。下列何種查核程序最能 有效偵查此項舞弊？', '["從付款交易中抽樣，並比對至請購單、訂購單、驗收報告、發票及支票副本", "向供應商發函詢證", "觀察收料倉庫並盤點已驗收之原料，並將盤點數量比對至驗收報告", "執行分析性測試，比較生產量、原料購買量及原料庫存水準，並調查其差異"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "1491f6c398c7", "answer_pdf_sha1": "19aa8285bb8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00954', 'cpa', 'cpa-moex-106-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員測試受查者編製的銀行調節表時，應取得下列何項資料以確認在途存款及未兌現支票的正 確性？', '["客戶在查核當期的交易紀錄及分類帳", "截止日後銀行對帳單", "客戶在查核次期的交易紀錄及分類帳", "客戶在查核當期所兌現之支票"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "1491f6c398c7", "answer_pdf_sha1": "19aa8285bb8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00955', 'cpa', 'cpa-moex-106-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員測試受查者之職能分工狀況時，最佳方式為何？', '["檢查相關文件", "詢問主要管理人員", "觀察相關職能的執行過程", "與其他受查之同業進行比較分析"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "1491f6c398c7", "answer_pdf_sha1": "19aa8285bb8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00956', 'cpa', 'cpa-moex-106-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列有關集團查核對組成個體執行工作之敘述何者正確？', '["決定是否具個別財務重要性之組成個體時，應以超過選用基準15%為依據", "對集團中具個別財務重要性之組成個體，僅能執行查核（full-scope audit）之工作", "對集團中具顯著風險之組成個體，僅能執行查核（full-scope audit）之工作", "對集團中未具個別財務重要性之組成個體，僅能執行核閱或集團層級分析性程序之工作"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "1491f6c398c7", "answer_pdf_sha1": "19aa8285bb8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00957', 'cpa', 'cpa-moex-106-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '關於控制測試之設計與執行，下列敘述何者較不適當？', '["控制測試可提供該控制在某一特定時間點有效運作之證據", "查核人員對控制執行有效性予以信賴之程度愈高，則須取得更具說服力之查核證據", "查核人員執行簡易測試（walk-through），其主要目的是測試控制執行有效性", "查核人員認為對個別聲明僅執行證實程序無法提供足夠及適切之查核證據時，應執行控制測試"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "1491f6c398c7", "answer_pdf_sha1": "19aa8285bb8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00958', 'cpa', 'cpa-moex-106-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '甲集團之銷貨型態主要分為工廠直接出貨及發貨倉銷貨兩類，其中，發貨倉銷貨收入於客戶提貨時 （移轉風險與報酬）始認列收入。該集團主要依發貨倉保管人所提供報表或其他資訊，以發貨倉之 存貨異動情形作為認列收入之依據。因發貨倉遍布全世界許多地區，各保管人所提供資訊之頻率與 報表內容亦有所不同，故此等認列收入流程通常涉及許多人工作業，加上該集團每日發貨倉銷貨交 易量龐大，且財務報表結束日前後之交易金額對合併財務報表之影響至為重大，故會計師認為發貨 倉銷貨之收入認列之查核為本年度查核中最為重要之事項。前述所提及之銷貨交易，最重要之聲明 為何？', '["發生", "完整性", "正確", "截止"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "1491f6c398c7", "answer_pdf_sha1": "19aa8285bb8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00959', 'cpa', 'cpa-moex-106-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員辨認並評估會計估計有關之重大不實表達風險時，應評估估計不確定性之程度，下列何者 不會影響估計不確定性之程度？', '["會計估計之性質", "與前期比較作成會計估計之方法是否變動", "會計估計之方法或模型被普遍使用之程度", "會計估計假設之主觀程度"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "1491f6c398c7", "answer_pdf_sha1": "19aa8285bb8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00960', 'cpa', 'cpa-moex-106-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列關於查核規劃之敘述何者正確？', '["查核人員應訂定查核計畫，以決定查核範圍、時間及方向，並據以擬訂整體查核策略", "主辦會計師對查核團隊成員之指導、監督及工作之複核，應規劃其性質、時間及範圍", "針對續任案件之查核規劃，通常於本期投入查核開始，並持續至當期查核案件完成為止", "查核人員於辨認及評估重大不實表達風險後，應考量重大性之決定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "1491f6c398c7", "answer_pdf_sha1": "19aa8285bb8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00961', 'cpa', 'cpa-moex-106-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列何種風險可藉由財務報表審計而獲得顯著降低？', '["固有風險（inherent risk）", "營業風險（business risk）", "資訊風險（information risk）", "查核風險（audit risk）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "1491f6c398c7", "answer_pdf_sha1": "19aa8285bb8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00962', 'cpa', 'cpa-moex-106-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列何者最不可能影響會計師的獨立性？', '["會計師為審計客戶保管錢財", "會計師的妹妹係委任簽證公司之董事長", "會計師於其負責查核之金融機構開立一般活期存款帳戶", "會計師以其就讀國中兒子的名義認購自己簽證之客戶公司發行的新股"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "1491f6c398c7", "answer_pdf_sha1": "19aa8285bb8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00963', 'cpa', 'cpa-moex-106-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列那一項屬於財務報表審計的先天性限制？', '["會計師必須協助編製財務報表", "會計師必須找出財務報表中之重大舞弊情事", "會計師必須與受查者間保持獨立性", "會計師必須對會計估計，進行專業評估與判斷"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "1491f6c398c7", "answer_pdf_sha1": "19aa8285bb8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00964', 'cpa', 'cpa-moex-106-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '依審計準則公報第59號「修正式查核意見」及第61號「繼續經營」之規定，下列敘述何者錯誤？', '["當所查核之財務報表因查核範圍受限制而無法取得足夠及適切之查核證據，但其影響為重大且廣 泛，會計師應出具否定意見", "當所查核之財務報表查核人員已取得足夠及適切之查核證據，採用繼續經營會計基礎係屬適當但 存在重大不確定性，若財務報表已作適當揭露，則會計師應出具無保留意見附加繼續經營有關之 重大不確定性段", "如果受查者已採用繼續經營會計基礎編製財務報表，而會計師已取得足夠及適切之查核證據，判 斷受查者採用繼續經營會計基礎編製財務報表非屬適當時，則應出具無法表示意見", "會計人員已取得足夠及適切之查核證據，判斷受查者採用繼續經營會計基礎編製財務報表係屬適 當，但導致繼續經營之能力可能產生重大疑慮之事項或情況仍存有重大不確定性時，如果財務報 表未作適當揭露而會計師認為該揭露之遺漏對財務報表之影響雖屬重大但並非廣泛，則應出具保 留意見 會計師判斷受查者採用繼續經營會計基礎編製財務報表非屬適當時，而若受查者已採用清算會計 基礎編製財務報表，則應出具否定意見"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "1491f6c398c7", "answer_pdf_sha1": "19aa8285bb8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00965', 'cpa', 'cpa-moex-106-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '若受查者採用線上即時作業系統（online real-time system），下列有關該系統之敘述那些正確？', '["相對於批次作業系統（batch system），使用批次控制的機會較少", "查核人員較可能使用測試資料（test data）法測試其內部控制的效果", "查核人員較可能使用整體測試設施（integrated test facility）法測試其內部控制的效果", "查核人員較可能使用平行模擬（parallel simulation）法測試其內部控制的效果 查核人員較可能使用嵌入查核模組（embedded audit module）法測試其內部控制的效果"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "1491f6c398c7", "answer_pdf_sha1": "19aa8285bb8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00966', 'cpa', 'cpa-moex-106-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列有關重大性之敘述何者正確？', '["某一事項對財務報表使用者而言是否屬重大之判斷，係以特定使用者對財務資訊之需求為考量依據", "金額低於所設定重大性之未更正不實表達，因金額微小查核人員均評估為不重大", "查核人員於本期查核過程中獲悉之資訊，導致重大性與查核規劃初始決定者有所不同時，應於次 期修正財務報表整體重大性", "受查者之股權結構及籌資方式可能影響決定財務報表整體重大性之基準 若受查者當期發生繼續營業單位稅前淨利異常之情況，查核人員可能根據常態化過去繼續營業單 位稅前淨利決定財務報表整體重大性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "1491f6c398c7", "answer_pdf_sha1": "19aa8285bb8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00967', 'cpa', 'cpa-moex-106-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '我國審計準則公報第1號「一般公認審計準則總綱」中，一般準則規定：', '["查核工作應由具備專門學識經驗及訓練者為之", "執行查核工作應盡專業上應有之注意", "若有助理人員，應善加督導", "承辦查核案件應設置工作底稿 撰寫報告時，應秉持超然獨立之精神"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "1491f6c398c7", "answer_pdf_sha1": "19aa8285bb8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
